const i="https://infinity-ai-backend.vercel.app/api/memory/ingest";chrome.runtime.onMessage.addListener((n,c,t)=>{if(n.action==="INGEST_MEMORY"){const{payload:o}=n;return console.log(`[InfinityAI Background] Sending memory ingestion request for: ${o.url}`),fetch(i,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(o)}).then(async e=>{if(!e.ok){const r=await e.text();throw new Error(r||`Status code ${e.status}`)}return e.json()}).then(e=>{console.log("[InfinityAI Background] Memory ingestion succeeded:",e),t({success:!0,data:e})}).catch(e=>{console.error("[InfinityAI Background] Ingestion request failed:",e),t({success:!1,error:e.message||"Cannot connect to backend server. Make sure the service is running."})}),!0}});
